const numbersToWords=i=>{const N=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(i<0x14)return N[i];if(i<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](i/0xa)]+(i%0xa?'\x20'+N[i%0xa]:'');if(i<0x3e8){const X=Math['floor'](i/0x64),h=i%0x64;return(0x1===X?'εκατό':0x2===X?'διακόσια':0x3===X?'τριακόσια':0x4===X?'τετρακόσια':0x5===X?'πεντακόσια':0x6===X?'εξακόσια':0x7===X?'επτακόσια':0x8===X?'οκτακόσια':0x9===X?'εννιακόσια':'')+(h?'\x20'+numbersToWords(h):'');}return i<0xf4240?numbersToWords(Math['floor'](i/0x3e8))+'\x20χιλιάδες'+(i%0x3e8?'\x20'+numbersToWords(i%0x3e8):''):numbersToWords(Math['floor'](i/0xf4240))+'\x20εκατομμύρια'+(i%0xf4240?'\x20'+numbersToWords(i%0xf4240):'');},numberToText=(i,N='money')=>{const X=Math['floor'](i),h=Math['round'](0x64*(i-X));let l=numbersToWords(X),G=h>0x0?numbersToWords(h):'';switch(N){case'money':return G?l+'\x20ευρώ\x20και\x20'+G+'\x20λεπτά':l+'\x20ευρώ';case'time':return G?l+'\x20ώρες\x20και\x20'+G+'\x20λεπτά':l+'\x20ώρες';default:return G?l+'\x20και\x20'+G:''+l;}};